SELECT wy.name FROM (SELECT name, SUM(number) AS wy_count FROM `bigquery-public-data.usa_names.usa_1910_current` WHERE year = 2021 AND gender = 'F' AND state = 'WY' GROUP BY name) wy JOIN (SELECT name, SUM(number) AS total_count FROM `bigquery-public-data.usa_names.usa_1910_current` WHERE year = 2021 AND gender = 'F' GROUP BY name) total ON wy.name = total.name ORDER BY wy.wy_count / total.total_count DESC LIMIT 1